import{_ as s,o as a,c as i,a0 as o}from"./chunks/framework.CEW4uG-d.js";const p=JSON.parse('{"title":"Blocking Methods","description":"","frontmatter":{},"headers":[],"relativePath":"guide/blocking-methods.md","filePath":"guide/blocking-methods.md"}'),t={name:"guide/blocking-methods.md"};function l(n,e,d,h,r,c){return a(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="blocking-methods" tabindex="-1">Blocking Methods <a class="header-anchor" href="#blocking-methods" aria-label="Permalink to &quot;Blocking Methods&quot;">​</a></h1><p>BlockGuard CLI offers two methods of blocking ads. You can use either method individually or combine them for maximum redundancy.</p><hr><h2 id="method-1-dns-proxy-recommended" tabindex="-1">Method 1: DNS Proxy (Recommended) <a class="header-anchor" href="#method-1-dns-proxy-recommended" aria-label="Permalink to &quot;Method 1: DNS Proxy (Recommended)&quot;">​</a></h2><p>This is the default mode of operation. BlockGuard binds to port 53 and acts as a local DNS proxy.</p><h3 id="how-it-works" tabindex="-1">How it works: <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works:&quot;">​</a></h3><ul><li>All system DNS queries go to BlockGuard.</li><li>If a domain matches block rules, BlockGuard returns <code>NXDOMAIN</code> (non-existent domain) or <code>0.0.0.0</code> (as configured).</li><li>If it is clean, it is resolved via upstream servers (Cloudflare/Google) and cached in-memory for speed.</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Enable DNS blocking (default: true)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blockguard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blocking.enabled</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span></span></code></pre></div><hr><h2 id="method-2-system-hosts-file-management" tabindex="-1">Method 2: System Hosts File Management <a class="header-anchor" href="#method-2-system-hosts-file-management" aria-label="Permalink to &quot;Method 2: System Hosts File Management&quot;">​</a></h2><p>This method writes rules directly to your system <code>/etc/hosts</code> (Linux/macOS) or <code>C:\\Windows\\System32\\drivers\\etc\\hosts</code> (Windows) file.</p><h3 id="how-it-works-1" tabindex="-1">How it works: <a class="header-anchor" href="#how-it-works-1" aria-label="Permalink to &quot;How it works:&quot;">​</a></h3><ul><li>When you start BlockGuard, it writes blocklists directly into the hosts file.</li><li>The operating system resolves these domains to <code>0.0.0.0</code> locally without making external network queries.</li><li>When you stop BlockGuard, it cleans up and restores your original hosts file.</li></ul><h3 id="how-to-enable" tabindex="-1">How to enable: <a class="header-anchor" href="#how-to-enable" aria-label="Permalink to &quot;How to enable:&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Enable hosts file management</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blockguard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hosts.manage</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">PERFORMANCE CONSIDERATION</p><p>Writing 200,000+ domains directly to the system hosts file can slow down DNS resolution on some older systems. The DNS Proxy method is highly recommended for general use.</p></div>`,16)])])}const m=s(t,[["render",l]]);export{p as __pageData,m as default};
